code_examples.code:
// In invoices.tsp, inside InvoiceEndpoints:
@post
@route("/my-action")
@summary("Perform my action")
@operationId("myInvoiceAction")
myAction(
  @path invoiceId: ULID,
  @body request: MyActionInput,
): Invoice | NotFoundError | CommonErrors;

// New models in the same file:
@friendlyName("MyActionInput")
model MyActionInput {
  @visibility(Lifecycle.Create)
  action: MyActionType;
}

@friendlyName("MyActionType")
@discriminated(#{ envelope: "none", discriminatorPropertyName: "kind" })
union MyActionType {
  optionA: MyActionTypeA,
  optionB: MyActionTypeB,
}

@friendlyName("MyActionTypeA")
model MyActionTypeA {
  kind: "optionA";
}

@friendlyName("MyActionTypeB")
model MyActionTypeB {
  kind: "optionB";
}

