#suppress "deprecated" "V1 Entitlements APIs will be removed on December 1st, 2025"
@friendlyName("EntitlementMyType")
model EntitlementMyType {
  type: EntitlementType.myType;
  ...OmitProperties<EntitlementMyTypeCreateInputs, "type" | "metadata" | "usagePeriod" | "featureKey" | "featureId">;
